/**
 * ═══════════════════════════════════════════════════════════════════════════
 * 📜 XUS MENU v6.0 — ULTRA INTELIGENTE CON EMOJIS REALES
 * ═══════════════════════════════════════════════════════════════════════════
 * 
 * CARACTERÍSTICAS:
 * - Muestra solo hábitos del bloque actual + pendientes del anterior
 * - Oculta automáticamente los que ya están marcados como TRUE
 * - Progreso en tiempo real del día completo
 * - Emojis exactos de tus 17 hábitos reales
 * - Bloques horarios alineados a tu agenda
 * - Vista adaptativa según la hora
 * 
 * ═══════════════════════════════════════════════════════════════════════════
 */

// ═══════════════════════════════════════════════════════════════════════════
// 1. CONFIGURACIÓN INICIAL
// ═══════════════════════════════════════════════════════════════════════════

const sheetsData = $input.all();
const now = new Date(new Date().toLocaleString("en-US", {timeZone: "America/Bogota"}));
const hora = now.getHours();
const minutos = now.getMinutes();
const horaDecimal = hora + (minutos / 60);
const todayNum = now.getDate().toString();

// ═══════════════════════════════════════════════════════════════════════════
// 2. FUNCIÓN: Verificar si un hábito está completado HOY
// ═══════════════════════════════════════════════════════════════════════════

function isCompleted(rowNumber) {
  for (const item of sheetsData) {
    const row = item.json;
    if (row.row_number === rowNumber) {
      const val = row[todayNum];
      if (!val) return false;
      const valStr = String(val).toUpperCase().trim();
      return ['TRUE', '1', 'SI', 'SÍ', 'VERDADERO', 'X', '✓', '✔'].includes(valStr);
    }
  }
  return false;
}

// ═══════════════════════════════════════════════════════════════════════════
// 3. DEFINICIÓN DE BLOQUES HORARIOS CON 17 HÁBITOS REALES
// ═══════════════════════════════════════════════════════════════════════════
// Nota: Los row_number van de 10 a 26 (17 hábitos)

const BLOQUES = [
  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 1: RITUAL DE GUERRA (5:50 - 7:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'ritual',
    nombre: '⛳ RITUAL DE GUERRA',
    mensaje: 'Arranca el día con fuerza absoluta:',
    inicio: 5.83,  // 5:50
    fin: 7.0,
    habitos: [
      { text: "⛳ Despertar 5:50", callback_data: "Despertar 5:50 a.m. ⛳", row: 10 },
      { text: "💪 100 Push Ups", callback_data: "100 Push Ups 💪", row: 11 },
      { text: "🐋 Cold Shower", callback_data: "Cold Shower 🐋", row: 12 },
      { text: "🎯 English Class", callback_data: "English Class 🎯", row: 13 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 2: ESCRITURA METAS (7:00 - 8:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'metas_manana',
    nombre: '🌬 ESCRITURA METAS',
    mensaje: 'Programa tu mente para ganar:',
    inicio: 7.0,
    fin: 8.0,
    habitos: [
      { text: "🌬 Metas X10", callback_data: "Escritura Metas X10 🌬", row: 14 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 3: DEEP WORK + PROSPECCIÓN (8:00 - 11:30)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'prospeccion',
    nombre: '📈 DEEP WORK',
    mensaje: 'Foco total. Generación de leads:',
    inicio: 8.0,
    fin: 11.5,
    habitos: [
      { text: "📈 Deep Work 50", callback_data: "Deep Work 50 Leads 📈", row: 15 },
      { text: "📈 Search 300", callback_data: "Search 300 Leads 📈", row: 16 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 4: RECARGA ANALÓGICA (11:30 - 13:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'recarga',
    nombre: '🐱‍👤 RECARGA',
    mensaje: 'Almuerzo sin pantallas. Desconexión:',
    inicio: 11.5,
    fin: 13.0,
    habitos: [
      { text: "🐱‍👤 Recarga Analógica", callback_data: "Recarga Analogica 🐱‍👤", row: 17 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 5: GESTIÓN (13:00 - 15:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'gestion',
    nombre: '🧨 GESTIÓN',
    mensaje: 'Respuestas y organización:',
    inicio: 13.0,
    fin: 15.0,
    habitos: [
      { text: "🧨 Respuestas", callback_data: "Gestion de Respuestas 🧨", row: 18 },
      { text: "🗂️ Create Carpets", callback_data: "Create Carpets 🗂️", row: 19 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 6: SEGUNDA RONDA (15:00 - 17:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'segunda_ronda',
    nombre: '⚡ SEGUNDA RONDA',
    mensaje: '30 leads más. No dejes dinero en la mesa:',
    inicio: 15.0,
    fin: 17.0,
    habitos: [
      { text: "⚡ 2da Ronda 30", callback_data: "Segunda Ronda 30 Leads ⚡", row: 20 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 7: ROLE PLAY (17:00 - 18:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'guion',
    nombre: '🐱‍🏍 GUIÓN H.T.',
    mensaje: 'Practica el cierre perfecto:',
    inicio: 17.0,
    fin: 18.0,
