      { text: "🐱‍🏍 Role Play H.T", callback_data: "Role Play Guion H.T 🐱‍🏍", row: 21 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 8: REGISTRO CRM (18:00 - 19:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'registro',
    nombre: '🐱‍👓 REGISTRO',
    mensaje: 'Lo que no se mide, no existe:',
