    fin: 19.0,
    habitos: [
      { text: "🐱‍👓 Registro Leads", callback_data: "Registro de Leads C. 🐱‍👓", row: 22 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 9: AUDITORÍA (19:00 - 20:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'auditoria',
    nombre: '🟡 AUDITORÍA',
    mensaje: 'Expectativa vs Realidad. ¿Cumpliste?',
    inicio: 19.0,
    fin: 20.0,
    habitos: [
      { text: "🟡 Auditoría", callback_data: "Auditoria Expectativa v.s Realidad 🟡", row: 23 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 10: AFIRMACIONES NOCTURNAS (20:00 - 20:30)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'afirmaciones',
    nombre: '🚀 AFIRMACIONES',
    mensaje: 'Reescribe tus metas. Visualiza:',
    inicio: 20.0,
    fin: 20.5,
    habitos: [
      { text: "🚀 Metas/Afirmaciones", callback_data: "Escribir Metas | Afirmaciones 🚀", row: 24 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 11: PLANEACIÓN (20:30 - 21:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'planeacion',
    nombre: '🐇 PLANEACIÓN',
    mensaje: 'Prepara el plan de mañana:',
    inicio: 20.5,
    fin: 21.0,
    habitos: [
      { text: "🐇 Planeación", callback_data: "Planeacion/Planificacion 🐇", row: 25 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 12: LECTURA (21:00 - 21:40)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'lectura',
    nombre: '🎯 LECTURA',
    mensaje: 'El Príncipe - 10 páginas mínimo:',
    inicio: 21.0,
    fin: 21.67, // 21:40
    habitos: [
      { text: "🎯 El Príncipe 10p", callback_data: "Lectura El Principe 10 Paginas 🎯", row: 26 }
    ]
  },

  // ─────────────────────────────────────────────────────────────────────────
  // BLOQUE 13: RUTINA NOCTURNA (21:40 - 23:00)
  // ─────────────────────────────────────────────────────────────────────────
  {
    id: 'rutina_noche',
    nombre: '🧥 RUTINA NOCTURNA',
    mensaje: 'Desconexión total:',
    inicio: 21.67,
    fin: 23.0,
    habitos: [
      { text: "🧥 Routine Face", callback_data: "Routine Face (Ice Cold Face) 🧥", row: 27 },
      { text: "♣ Cama 9:40", callback_data: "Ir a la Cama a las 9:40 p.m. ♣", row: 28 }
    ]
  }
];

// ═══════════════════════════════════════════════════════════════════════════
// 4. ENCONTRAR BLOQUE ACTUAL Y ANTERIOR
// ═══════════════════════════════════════════════════════════════════════════

let bloqueActualIdx = -1;

// Buscar el bloque actual según la hora
for (let i = 0; i < BLOQUES.length; i++) {
  if (horaDecimal >= BLOQUES[i].inicio && horaDecimal < BLOQUES[i].fin) {
    bloqueActualIdx = i;
    break;
  }
}

// Si no encontró bloque exacto (entre bloques o fuera de rango)
if (bloqueActualIdx === -1) {
  if (horaDecimal < 5.83) {
    // Antes del primer bloque
    bloqueActualIdx = 0;
  } else if (horaDecimal >= 23.0) {
    // Después del último bloque
    bloqueActualIdx = BLOQUES.length - 1;
  } else {
    // Entre bloques - buscar el siguiente
    for (let i = 0; i < BLOQUES.length - 1; i++) {
      if (horaDecimal >= BLOQUES[i].fin && horaDecimal < BLOQUES[i + 1].inicio) {
        bloqueActualIdx = i + 1; // Mostrar el siguiente
        break;
      }
    }
  }
}

const bloqueActual = BLOQUES[bloqueActualIdx];
const bloqueAnterior = bloqueActualIdx > 0 ? BLOQUES[bloqueActualIdx - 1] : null;

// ═══════════════════════════════════════════════════════════════════════════
// 5. FILTRAR HÁBITOS PENDIENTES (NO COMPLETADOS)
// ═══════════════════════════════════════════════════════════════════════════

function getHabitosPendientes(bloque) {
  if (!bloque) return [];
  return bloque.habitos.filter(h => !isCompleted(h.row));
}

const pendientesActual = getHabitosPendientes(bloqueActual);
const pendientesAnterior = getHabitosPendientes(bloqueAnterior);

// ═══════════════════════════════════════════════════════════════════════════
// 6. CONSTRUIR TECLADO INLINE (BOTONES)
// ═══════════════════════════════════════════════════════════════════════════

let botones = [];
let titulo = bloqueActual.nombre;
let mensaje = bloqueActual.mensaje;

// Contador de completados del bloque actual
const totalActual = bloqueActual.habitos.length;
const completadosActual = totalActual - pendientesActual.length;

// ─────────────────────────────────────────────────────────────────────────
// 6.1 AÑADIR PENDIENTES DEL BLOQUE ANTERIOR
// ─────────────────────────────────────────────────────────────────────────

if (pendientesAnterior.length > 0) {
  mensaje += `\n\n⚠️ _Pendientes de ${bloqueAnterior.nombre}:_`;

  // Agrupar en filas de 2 botones
  for (let i = 0; i < pendientesAnterior.length; i += 2) {
    const fila = [pendientesAnterior[i]];
    if (pendientesAnterior[i + 1]) {
      fila.push(pendientesAnterior[i + 1]);
    }
    botones.push(fila);
  }
}

// ─────────────────────────────────────────────────────────────────────────
// 6.2 AÑADIR PENDIENTES DEL BLOQUE ACTUAL
// ─────────────────────────────────────────────────────────────────────────

if (pendientesActual.length > 0) {
  // Si ya mostramos pendientes anteriores, agregar separador
  if (pendientesAnterior.length > 0) {
    botones.push([{ 
      text: `─── AHORA (${completadosActual}/${totalActual} ✓) ───`, 
      callback_data: 'separador' 
    }]);
  }

  // Agrupar en filas de 2 botones
  for (let i = 0; i < pendientesActual.length; i += 2) {
    const fila = [pendientesActual[i]];
    if (pendientesActual[i + 1]) {
      fila.push(pendientesActual[i + 1]);
    }
    botones.push(fila);
  }
} else if (pendientesAnterior.length === 0) {
  // ─────────────────────────────────────────────────────────────────────────
  // 6.3 ¡TODO COMPLETADO EN ESTE BLOQUE!
  // ─────────────────────────────────────────────────────────────────────────

  mensaje = `✅ *¡BLOQUE COMPLETADO!*\n\nTodos los hábitos de ${bloqueActual.nombre} están listos.`;

  // Buscar siguiente bloque con pendientes
  let siguienteBloqueConPendientes = null;
  for (let i = bloqueActualIdx + 1; i < BLOQUES.length; i++) {
    const pendientes = getHabitosPendientes(BLOQUES[i]);
    if (pendientes.length > 0) {
      siguienteBloqueConPendientes = BLOQUES[i];
      mensaje += `\n\n🔜 _Próximo: ${siguienteBloqueConPendientes.nombre}_`;

      // Mostrar pendientes del siguiente bloque
      for (let j = 0; j < pendientes.length; j += 2) {
        const fila = [pendientes[j]];
        if (pendientes[j + 1]) {
          fila.push(pendientes[j + 1]);
        }
        botones.push(fila);
      }
      break;
    }
  }

  // Si no hay más bloques con pendientes
  if (!siguienteBloqueConPendientes) {
    mensaje += `\n\n🏆 *¡DÍA PERFECTO!*\nTodos los hábitos completados.`;
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// 7. ACCIONES RÁPIDAS (SIEMPRE DISPONIBLES)
// ═══════════════════════════════════════════════════════════════════════════

botones.push([
  { text: "📊 Análisis Diario", callback_data: "analisis de hoy" },
  { text: "🎵 Imperial March", callback_data: "ponme imperial" }
]);

// ═══════════════════════════════════════════════════════════════════════════
// 8. CALCULAR PROGRESO GLOBAL DEL DÍA
// ═══════════════════════════════════════════════════════════════════════════

let totalHabitos = 0;
let completados = 0;

BLOQUES.forEach(b => {
  b.habitos.forEach(h => {
    totalHabitos++;
    if (isCompleted(h.row)) {
      completados++;
    }
  });
});

const porcentaje = totalHabitos > 0 ? Math.round((completados / totalHabitos) * 100) : 0;
const pendientesTotal = totalHabitos - completados;

// ═══════════════════════════════════════════════════════════════════════════
// 9. CONSTRUIR MENSAJE FINAL
// ═══════════════════════════════════════════════════════════════════════════

const horaStr = String(hora).padStart(2, '0') + ':' + String(minutos).padStart(2, '0');

// Emoji dinámico según progreso
let emojiProgreso = '🟥';
if (porcentaje >= 80) emojiProgreso = '🟩';
else if (porcentaje >= 50) emojiProgreso = '🟨';
else if (porcentaje >= 20) emojiProgreso = '🟧';

// Barra de progreso visual
const bloquesFilled = Math.floor(porcentaje / 10);
const bloquesEmpty = 10 - bloquesFilled;
const barraProgreso = '▓'.repeat(bloquesFilled) + '░'.repeat(bloquesEmpty);

let textoFinal = `*${titulo}*\n`;
textoFinal += `🕐 ${horaStr} | ${emojiProgreso} ${completados}/${totalHabitos} (${porcentaje}%)\n`;
textoFinal += `${barraProgreso}\n\n`;
textoFinal += mensaje;

// Añadir motivación según progreso
if (porcentaje === 100) {
  textoFinal += `\n\n💀 _Ejecución total. Esto es disciplina de élite._`;
} else if (porcentaje >= 80) {
  textoFinal += `\n\n🔥 _¡Casi perfecto! Solo ${pendientesTotal} más._`;
} else if (porcentaje >= 50) {
  textoFinal += `\n\n⚡ _Buen ritmo. Mantén el enfoque._`;
}

// ═══════════════════════════════════════════════════════════════════════════
// 10. RETORNAR RESULTADO
// ═══════════════════════════════════════════════════════════════════════════

return [{
  json: {
    moduleType: 'menu',
    active: true,
    textResponse: textoFinal,
    menuButtons: botones,
    telegramOptions: {
      parseMode: 'Markdown',
      hasButtons: true,
      inlineKeyboard: botones
    },
    // Metadata para debugging
    _debug: {
      horaActual: horaStr,
      bloqueActual: bloqueActual.id,
      totalHabitos: totalHabitos,
      completados: completados,
      porcentaje: porcentaje,
      pendientesActual: pendientesActual.length,
      pendientesAnterior: pendientesAnterior.length
    }
  }
}];
